// TypeScript's MaxPriorityQueue implementation
class MaxPriorityQueue<T> {
    private heap: T[];
    private size: number;

    constructor() {
        this.heap = [];
        this.size = 0;
    }

    enqueue(element: T): void {
        this.heap.push(element);
        this.size++;
        this.heapifyUp(this.size - 1);
    }

    dequeue(): T | undefined {
        if (this.size === 0) return undefined;
        const element = this.heap[0];
        this.heap[0] = this.heap[this.size - 1];
        this.size--;
        this.heapifyDown(0);
        return element;
    }

    private heapifyUp(index: number): void {
        while (index > 0) {
            const parentIndex = Math.floor((index - 1) / 2);
            if (this.heap[parentIndex] <= this.heap[index]) {
                [this.heap[parentIndex], this.heap[index]] = [this.heap[index], this.heap[parentIndex]];
                index = parentIndex;
            } else {
                break;
            }
        }
    }

    private heapifyDown(index: number): void {
        while (index < this.size) {
            const leftChildIndex = 2 * index + 1;
            const rightChildIndex = 2 * index + 2;
            let largestIndex = index;

            if (leftChildIndex < this.size && this.heap[leftChildIndex] > this.heap[largestIndex]) {
                largestIndex = leftChildIndex;
            }

            if (rightChildIndex < this.size && this.heap[rightChildIndex] > this.heap[largestIndex]) {
                largestIndex = rightChildIndex;
            }

            if (largestIndex !== index) {
                [this.heap[index], this.heap[largestIndex]] = [this.heap[largestIndex], this.heap[index]];
                index = largestIndex;
            } else {
                break;
            }
        }
    }
}
